import React, { useState, useEffect, useRef } from 'react';
import {
  MapPin,
  Navigation,
  Phone,
  Clock,
  Star,
  ExternalLink,
  Loader,
  Search,
  X
} from 'lucide-react';

const MapView = ({ 
  latitude, 
  longitude, 
  offices = [],
  onLocationSelect,
  height = '500px'
}) => {
  const mapRef = useRef(null);
  const [map, setMap] = useState(null);
  const [markers, setMarkers] = useState([]);
  const [selectedOffice, setSelectedOffice] = useState(null);
  const [userLocation, setUserLocation] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);

  // Initialize map
  useEffect(() => {
    if (!window.google || !mapRef.current) return;

    const mapOptions = {
      center: { lat: latitude || 20.5937, lng: longitude || 78.9629 },
      zoom: 10,
      styles: [
        {
          featureType: 'poi',
          elementType: 'labels',
          stylers: [{ visibility: 'off' }]
        }
      ],
      mapTypeControl: true,
      fullscreenControl: true,
      streetViewControl: false
    };

    const newMap = new window.google.maps.Map(mapRef.current, mapOptions);
    setMap(newMap);

    // Add user location marker if available
    if (latitude && longitude) {
      addUserLocationMarker(newMap, latitude, longitude);
    }

  }, [latitude, longitude]);

  // Add markers for offices
  useEffect(() => {
    if (!map || !offices.length) return;

    // Clear existing markers
    markers.forEach(marker => marker.setMap(null));
    
    const newMarkers = offices.map((office, index) => {
      const marker = new window.google.maps.Marker({
        position: { lat: office.latitude, lng: office.longitude },
        map: map,
        title: office.name,
        animation: window.google.maps.Animation.DROP,
        icon: {
          url: 'https://maps.google.com/mapfiles/ms/icons/green-dot.png',
          scaledSize: new window.google.maps.Size(40, 40)
        }
      });

      // Add info window
      const infoWindow = new window.google.maps.InfoWindow({
        content: createInfoWindowContent(office)
      });

      marker.addListener('click', () => {
        infoWindow.open(map, marker);
        setSelectedOffice(office);
      });

      return marker;
    });

    setMarkers(newMarkers);

    // Fit bounds to show all markers
    if (offices.length > 0) {
      const bounds = new window.google.maps.LatLngBounds();
      offices.forEach(office => {
        bounds.extend({ lat: office.latitude, lng: office.longitude });
      });
      if (userLocation) {
        bounds.extend({ lat: userLocation.lat, lng: userLocation.lng });
      }
      map.fitBounds(bounds);
    }

  }, [map, offices, userLocation]);

  const addUserLocationMarker = (mapInstance, lat, lng) => {
    const userMarker = new window.google.maps.Marker({
      position: { lat, lng },
      map: mapInstance,
      title: 'Your Location',
      icon: {
        path: window.google.maps.SymbolPath.CIRCLE,
        scale: 10,
        fillColor: '#4285F4',
        fillOpacity: 1,
        strokeColor: '#FFFFFF',
        strokeWeight: 2,
      },
      zIndex: 999
    });

    setUserLocation({ lat, lng });
    setMarkers(prev => [...prev, userMarker]);
  };

  const createInfoWindowContent = (office) => {
    return `
      <div style="padding: 10px; max-width: 250px;">
        <h3 style="font-weight: bold; margin-bottom: 5px;">${office.name}</h3>
        <p style="color: #666; margin-bottom: 5px;">${office.address || ''}</p>
        ${office.phone ? `<p style="color: #666;">📞 ${office.phone}</p>` : ''}
        ${office.distance ? `<p style="color: #666;">📍 ${office.distance_text}</p>` : ''}
        <a href="https://www.google.com/maps/dir/?api=1&destination=${office.latitude},${office.longitude}" 
           target="_blank" 
           style="color: #4CAF50; text-decoration: none; display: inline-block; margin-top: 5px;">
          Get Directions →
        </a>
      </div>
    `;
  };

  const getUserLocation = () => {
    setLoading(true);
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          if (map) {
            map.setCenter({ lat: latitude, lng: longitude });
            map.setZoom(12);
            addUserLocationMarker(map, latitude, longitude);
          }
          if (onLocationSelect) {
            onLocationSelect(latitude, longitude);
          }
          setLoading(false);
        },
        (error) => {
          console.error('Error getting location:', error);
          alert('Unable to get your location. Please check location permissions.');
          setLoading(false);
        }
      );
    } else {
      alert('Geolocation is not supported by your browser');
      setLoading(false);
    }
  };

  const searchLocation = async () => {
    if (!searchQuery.trim() || !window.google) return;

    setLoading(true);
    try {
      const geocoder = new window.google.maps.Geocoder();
      geocoder.geocode({ address: searchQuery }, (results, status) => {
        if (status === 'OK' && results[0]) {
          const location = results[0].geometry.location;
          map.setCenter(location);
          map.setZoom(12);
          
          // Add temporary marker
          new window.google.maps.Marker({
            position: location,
            map: map,
            title: searchQuery,
            animation: window.google.maps.Animation.DROP
          });

          if (onLocationSelect) {
            onLocationSelect(location.lat(), location.lng());
          }

          setSearchResults([]);
        } else {
          alert('Location not found');
        }
        setLoading(false);
      });
    } catch (error) {
      console.error('Error searching location:', error);
      setLoading(false);
    }
  };

  const getDirections = (office) => {
    if (!userLocation) {
      alert('Please enable location services to get directions');
      return;
    }

    const url = `https://www.google.com/maps/dir/?api=1&origin=${userLocation.lat},${userLocation.lng}&destination=${office.latitude},${office.longitude}`;
    window.open(url, '_blank');
  };

  return (
    <div className="bg-white rounded-xl shadow-lg overflow-hidden border border-gray-200">
      {/* Map Header */}
      <div className="p-4 bg-gradient-to-r from-green-50 to-emerald-50 border-b">
        <div className="flex items-center justify-between">
          <h3 className="font-semibold text-gray-900 flex items-center">
            <MapPin className="h-5 w-5 text-green-600 mr-2" />
            Nearby Agricultural Offices
          </h3>
          
          <div className="flex items-center space-x-2">
            {/* Search Input */}
            <div className="relative">
              <input
                type="text"
                placeholder="Search location..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && searchLocation()}
                className="pl-3 pr-8 py-1.5 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500"
              />
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery('')}
                  className="absolute right-2 top-2 text-gray-400 hover:text-gray-600"
                >
                  <X className="h-4 w-4" />
                </button>
              )}
            </div>
            
            <button
              onClick={searchLocation}
              disabled={loading}
              className="p-2 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:opacity-50"
            >
              <Search className="h-4 w-4" />
            </button>
            
            <button
              onClick={getUserLocation}
              disabled={loading}
              className="flex items-center px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
            >
              {loading ? (
                <Loader className="h-4 w-4 animate-spin mr-2" />
              ) : (
                <Navigation className="h-4 w-4 mr-2" />
              )}
              My Location
            </button>
          </div>
        </div>
      </div>

      {/* Map Container */}
      <div 
        ref={mapRef} 
        style={{ height, width: '100%' }}
        className="relative"
      />

      {/* Offices List */}
      {offices.length > 0 && (
        <div className="border-t max-h-96 overflow-y-auto">
          <div className="p-4 bg-gray-50 border-b">
            <h4 className="font-medium text-gray-700">
              Found {offices.length} nearby offices
            </h4>
          </div>
          
          <div className="divide-y">
            {offices.map((office, index) => (
              <div
                key={index}
                className={`p-4 hover:bg-gray-50 cursor-pointer transition-colors ${
                  selectedOffice?.name === office.name ? 'bg-green-50' : ''
                }`}
                onClick={() => {
                  setSelectedOffice(office);
                  if (map) {
                    map.setCenter({ lat: office.latitude, lng: office.longitude });
                    map.setZoom(15);
                  }
                }}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <h5 className="font-medium text-gray-900">{office.name}</h5>
                    <p className="text-sm text-gray-600 mt-1">{office.address}</p>
                    
                    <div className="flex items-center space-x-4 mt-2">
                      {office.distance && (
                        <span className="text-xs text-gray-500 flex items-center">
                          <Navigation className="h-3 w-3 mr-1" />
                          {office.distance_text}
                        </span>
                      )}
                      {office.phone && (
                        <span className="text-xs text-gray-500 flex items-center">
                          <Phone className="h-3 w-3 mr-1" />
                          {office.phone}
                        </span>
                      )}
                      {office.rating && (
                        <span className="text-xs text-gray-500 flex items-center">
                          <Star className="h-3 w-3 mr-1 text-yellow-400" />
                          {office.rating} ({office.user_ratings_total})
                        </span>
                      )}
                    </div>
                  </div>
                  
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      getDirections(office);
                    }}
                    className="ml-4 p-2 text-green-600 hover:bg-green-50 rounded-lg transition-colors"
                    title="Get directions"
                  >
                    <ExternalLink className="h-5 w-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Selected Office Details */}
      {selectedOffice && (
        <div className="p-4 bg-green-50 border-t">
          <div className="flex items-start justify-between">
            <div>
              <h4 className="font-semibold text-gray-900">{selectedOffice.name}</h4>
              <p className="text-sm text-gray-700 mt-1">{selectedOffice.address}</p>
              
              {selectedOffice.phone && (
                <p className="text-sm text-gray-700 mt-2">
                  <Phone className="h-4 w-4 inline mr-1" />
                  {selectedOffice.phone}
                </p>
              )}
              
              {selectedOffice.distance && (
                <p className="text-sm text-gray-700 mt-1">
                  <Navigation className="h-4 w-4 inline mr-1" />
                  {selectedOffice.distance_text} away
                </p>
              )}
            </div>
            
            <button
              onClick={() => setSelectedOffice(null)}
              className="text-gray-400 hover:text-gray-600"
            >
              <X className="h-5 w-5" />
            </button>
          </div>
          
          <div className="mt-4 flex space-x-3">
            <a
              href={`https://www.google.com/maps/dir/?api=1&destination=${selectedOffice.latitude},${selectedOffice.longitude}`}
              target="_blank"
              rel="noopener noreferrer"
              className="flex-1 text-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700"
            >
              Get Directions
            </a>
            {selectedOffice.phone && (
              <a
                href={`tel:${selectedOffice.phone}`}
                className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50"
              >
                Call
              </a>
            )}
          </div>
        </div>
      )}

      {/* Map Legend */}
      <div className="p-3 bg-gray-50 border-t text-xs text-gray-500 flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <div className="flex items-center">
            <div className="w-3 h-3 bg-blue-500 rounded-full mr-1"></div>
            <span>Your Location</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-green-500 rounded-full mr-1"></div>
            <span>Agriculture Office</span>
          </div>
        </div>
        <span>Powered by Google Maps</span>
      </div>
    </div>
  );
};

export default MapView;
